import { env } from "@/env";
import { buildLoginStartPath, type LoginOptions } from "@/lib/auth";
import { logServerErrorToRollbar } from "@/server/rollbar-server.server";
import {
  useAccountSession,
  useAuthTokenSession,
  useRefreshTokenSession,
} from "@/server/session.server";
import { redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";

export const redirectIfAuthenticated = createServerFn().handler(async () => {
  const session = await useAuthTokenSession();
  const hasAuthToken = !!session.data.authToken;

  if (env.VITE_TEMP_BYPASS_AUTH) {
    return;
  }

  if (hasAuthToken) {
    throw redirect({
      to: "/",
    });
  }
});

export async function initiateLogin(options: LoginOptions = {}): Promise<void> {
  window.location.assign(
    buildLoginStartPath({
      identityProvider: options.identityProvider,
    }),
  );
}

export const performLogout = createServerFn({ method: "POST" }).handler(
  async () => {
    await fetch(`${env.AUTH_APP_URL}/logout`, { method: "POST" });

    const [authTokenSession, refreshTokenSession, accountSession] =
      await Promise.all([
        useAuthTokenSession(),
        useRefreshTokenSession(),
        useAccountSession(),
      ]);

    const leftovers = [
      authTokenSession.data.authToken ? "authToken" : null,
      refreshTokenSession.data.refreshToken ? "refreshToken" : null,
      accountSession.data.accountId ? "__session" : null,
    ].filter((name): name is string => name !== null);

    if (leftovers.length > 0) {
      logServerErrorToRollbar(
        new Error(
          `auth cookies not cleared after /logout: ${leftovers.join(", ")}`,
        ),
      );
    }
  },
);

