export type LoginStartOptions = {
  identityProvider?: "Google";
  redirectTo?: string;
  screenHint?: "sign_up";
};

export interface LoginOptions {
  identityProvider?: "Google";
  screenHint?: "sign_up";
}

export function buildLoginStartPath(options: LoginStartOptions = {}) {
  const searchParams = new URLSearchParams();

  if (options.identityProvider) {
    searchParams.set("identity_provider", options.identityProvider);
  }

  if (options.redirectTo) {
    searchParams.set("redirect_to", options.redirectTo);
  }

  if (options.screenHint) {
    searchParams.set("screen_hint", options.screenHint);
  }

  const search = searchParams.toString();
  return search ? `/oauth/start?${search}` : "/oauth/start";
}

